// Chunk extracted text, embed with Ollama, store in Qdrant
const OLLAMA = 'http://localhost:11434';
const QDRANT = 'http://localhost:6333';

const item = $input.first();
const fullText = (item.json.data || '').trim();
const fileName = $('Read PDF File').first().json.fileName || 'uploaded.pdf';

if (fullText.length < 30) {
  return [{ json: { error: 'Text too short', length: fullText.length } }];
}

const docId = `doc_${Date.now()}`;
const chunks = [];
let start = 0, idx = 0;

while (start < fullText.length) {
  let end = Math.min(start + 500, fullText.length);
  if (end < fullText.length) {
    const bp = Math.max(fullText.lastIndexOf('.', end), fullText.lastIndexOf('\n', end));
    if (bp > start + 200) end = bp + 1;
  }
  const t = fullText.substring(start, end).trim();
  if (t.length > 20) chunks.push({ text: t, idx: idx++ });
  start = end - 100;
  if (end >= fullText.length) break;
}

let ok = 0, errs = [];
for (const c of chunks) {
  try {
    const emb = await this.helpers.httpRequest({
      method: 'POST', url: `${OLLAMA}/api/embeddings`,
      body: { model: 'nomic-embed-text', prompt: c.text },
      headers: { 'Content-Type': 'application/json' },
      timeout: 60000
    });
    if (!emb.embedding) { errs.push(`chunk ${c.idx}: no embedding`); continue; }

    let h = 0;
    for (let i = 0; i < docId.length; i++) h = ((h << 5) - h) + docId.charCodeAt(i) & 0x7fffffff;

    await this.helpers.httpRequest({
      method: 'PUT', url: `${QDRANT}/collections/pdf_rag/points`,
      body: { points: [{ id: h + c.idx, vector: emb.embedding, payload: {
        text: c.text, document_id: docId, file_name: fileName,
        chunk_index: c.idx, source: fileName,
        uploaded_at: new Date().toISOString(), total_chunks: chunks.length
      }}]},
      headers: { 'Content-Type': 'application/json' }, timeout: 30000
    });
    ok++;
  } catch(e) { errs.push(`chunk ${c.idx}: ${e.message}`); }
}

return [{ json: {
  status: ok > 0 ? 'success' : 'failed',
  chunks_stored: ok, total_chunks: chunks.length,
  document_id: docId, file_name: fileName,
  text_length: fullText.length,
  errors: errs.length ? errs : undefined
}}];
